async #getPathsForRoute(route: RouteData): Promise<PathWithRoute[]> {
	const paths: PathWithRoute[] = [];
	const manifest = this.#app.manifest;
	const routeCache = this.#app.pipeline.routeCache;

	// Static route - single pathname
	if (route.pathname) {
		paths.push({ pathname: route.pathname, route });
		return paths;
	}

	// Dynamic route - need to call getStaticPaths
	// Use pipeline.getComponentByRoute which handles redirects and fallbacks
	const componentInstance = await this.#app.pipeline.getComponentByRoute(route);

	// Determine which route to use for getStaticPaths
	const routeToProcess = routeIsRedirect(route)
		? route.redirectRoute
		: routeIsFallback(route)
			? getFallbackRoute(route, manifest.routes)
			: route;

	const actualRoute = routeToProcess ?? route;

	// Use callGetStaticPaths to populate the route cache
	const staticPaths = await callGetStaticPaths({
		mod: componentInstance,
		route: actualRoute,
		routeCache,
		ssr: manifest.serverLike,
		base: manifest.base,
		trailingSlash: manifest.trailingSlash,
	});

	// Convert params to pathnames using stringifyParams
	for (const staticPath of staticPaths) {
		const pathname = stringifyParams(staticPath.params, route, manifest.trailingSlash);
		paths.push({ pathname, route });
	}

	return paths;
}

async function callComponentAsTemplateResultOrResponse(
	result: SSRResult,
	componentFactory: AstroComponentFactory,
	props: any,
	children: any,
	route?: RouteData,
) {
	const factoryResult = await componentFactory(result, props, children);

	if (factoryResult instanceof Response) {
		return factoryResult;
	}
	// we check if the component we attempt to render is a head+content
	else if (isHeadAndContent(factoryResult)) {
		// we make sure that content is valid template result
		if (!isRenderTemplateResult(factoryResult.content)) {
			throw new AstroError({
				...AstroErrorData.OnlyResponseCanBeReturned,
				message: AstroErrorData.OnlyResponseCanBeReturned.message(
					route?.route,
					typeof factoryResult,
				),
				location: {
					file: route?.component,
				},
			});
		}

		// return the content
		return factoryResult.content;
	} else if (!isRenderTemplateResult(factoryResult)) {
		throw new AstroError({
			...AstroErrorData.OnlyResponseCanBeReturned,
			message: AstroErrorData.OnlyResponseCanBeReturned.message(route?.route, typeof factoryResult),
			location: {
				file: route?.component,
			},
		});
	}

	return factoryResult;
}

async function getContentEntryModule(
	params: GetEntryModuleParams<ContentEntryType>,
): Promise<ContentEntryModule> {
	const { fileId, contentDir, pluginContext } = params;
	const { collectionConfig, entryConfig, entry, rawContents, collection } =
		await getEntryModuleBaseInfo(params);

	const {
		rawData,
		data: unvalidatedData,
		body,
		slug: frontmatterSlug,
	} = await entryConfig.getEntryInfo({
		fileUrl: pathToFileURL(fileId),
		contents: rawContents,
	});
	const _internal = { filePath: fileId, rawData };
	const { id, slug: generatedSlug } = getContentEntryIdAndSlug({ entry, contentDir, collection });

	const slug = parseEntrySlug({
		id,
		collection,
		generatedSlug,
		frontmatterSlug,
	});

	const data = collectionConfig
		? await getEntryData(
				{ id, collection, _internal, unvalidatedData },
				collectionConfig,
				params.shouldEmitFile,
				pluginContext,
			)
		: unvalidatedData;

	const contentEntryModule: ContentEntryModule = {
		id,
		slug,
		collection,
		data,
		body,
		_internal,
	};

	return contentEntryModule;
}

function resolveNext(
	path: string,
	graph: Map<string, { destination: string; id: string }>,
	patterns: CompiledPatternRedirect[],
	edges?: RedirectEdge[],
): { destination: string; id: string } | null {
	// Exact match (fast) — works for both real paths and template strings
	const exact = graph.get(path);
	if (exact) return exact;

	if (!path.includes("[")) {
		// Concrete path — try pattern matching directly
		for (const pr of patterns) {
			const params = matchPattern(pr.compiled, path);
			if (params) {
				const resolved = interpolateDestination(pr.destination, params);
				return { destination: resolved, id: pr.id };
			}
		}
	} else {
		// Template string — generate representative paths and test against patterns
		const representatives = generateRepresentatives(path, edges);
		for (const pr of patterns) {
			for (const rep of representatives) {
				const params = matchPattern(pr.compiled, rep);
				if (params) {
					const resolved = interpolateDestination(pr.destination, params);
					return { destination: resolved, id: pr.id };
				}
			}
		}
	}

	return null;
}

export function toHttpResponse(err: unknown): Response {
	// Browser security headers (DS protocol §12.7) — set on every error
	// response so stream-endpoint errors thrown before the protocol layer
	// (e.g. run lookups) still carry them.
	const baseHeaders: Record<string, string> = {
		'content-type': 'application/json',
		'x-content-type-options': 'nosniff',
		'cross-origin-resource-policy': 'cross-origin',
	};
	if (isFlueError(err)) {
		const isHttp = err instanceof FlueHttpError;
		const status = isHttp ? err.status : 500;
		const headers = { ...baseHeaders };
		if (isHttp && err.headers) {
			Object.assign(headers, err.headers);
		}
		// Log non-HTTP FlueErrors that bubbled up to the HTTP layer — they
		// weren't constructed with HTTP semantics in mind, so it's worth
		// surfacing them in logs even though we render their message.
		if (!isHttp) {
			flueLog.error(err);
		}
		return new Response(JSON.stringify(envelope(err)), { status, headers });
	}
	// Non-FlueError: log everything, leak nothing.
	flueLog.error(err);
	return new Response(JSON.stringify(GENERIC_INTERNAL), {
		status: 500,
		headers: baseHeaders,
	});
}

export function generateSandboxRunnerModule(sandboxRunner?: string, sandbox?: boolean): string {
	if (!sandboxRunner) {
		// No sandbox runner configured - sandboxed plugins disabled
		return `
// No sandbox runner configured - sandboxed plugins disabled
import { createNoopSandboxRunner } from "emdash";

export const createSandboxRunner = createNoopSandboxRunner;
export const sandboxEnabled = false;
`;
	}

	if (sandbox === false) {
		// sandbox: false escape hatch - plugins are loaded but run in-process
		// (no isolation, for debugging)
		return `
// Sandbox explicitly disabled (sandbox: false) - plugins run in-process
import { createNoopSandboxRunner } from "emdash";

export const createSandboxRunner = createNoopSandboxRunner;
export const sandboxEnabled = true;
export const sandboxBypassed = true;
`;
	}

	return `
// Auto-generated sandbox runner module
import { createSandboxRunner as _createSandboxRunner } from "${sandboxRunner}";

export const createSandboxRunner = _createSandboxRunner;
export const sandboxEnabled = true;
`;
}

export async function run(ctx: FlueContext) {
	// Pretend we tried to call a flaky downstream service and it
	// threw. We catch the error so the run continues, but we still
	// want it captured in Sentry as an exception.
	try {
		throw new TypeError('downstream service returned an unexpected shape');
	} catch (error) {
		ctx.log.error('flaky downstream call failed; continuing with fallback', {
			error,
			service: 'fictional-pricing-api',
			retriable: false,
		});
	}

	// A second flavor: no `error` attribute, just a structured
	// message. The bridge captures this as `Sentry.captureMessage`
	// at `error` level, with the attributes attached as scope
	// context.
	ctx.log.error('low-confidence model output rejected', {
		confidence: 0.21,
		threshold: 0.5,
		action: 'fell back to deterministic path',
	});

	return {
		ok: true,
		id: ctx.id,
		// In a real handler, this would be the fallback result.
		fallbackUsed: true,
	};
}

function wysiwyg(opts: WYSIWYGSchemaOptions = {}): StudioCMSPluginDef {
	// Resolve the path to the current file
	const { resolve } = createResolver(import.meta.url);

	// Validate and parse the provided options using the WYSIWYG schema
	const options = Schema.decodeSync(WYSIWYGSchema)(opts);

	// Define the package identifier
	const packageIdentifier = '@studiocms/wysiwyg';

	// Return the plugin configuration
	return definePlugin({
		identifier: packageIdentifier,
		name: 'StudioCMS WYSIWYG Editor',
		hooks: {
			'studiocms:astro-config': async ({ addIntegrations }) => {
				// Add the WYSIWYG editor integration to the Astro configuration
				addIntegrations(internalWysiwygIntegration(packageIdentifier, options));
			},
			'studiocms:rendering': async ({ setRendering }) => {
				// Set the rendering configuration for the WYSIWYG editor
				// This will allow the editor to be rendered in the StudioCMS environment
				// and provide the necessary components for the editor.
				setRendering({
					pageTypes: [
						{
							identifier: 'studiocms/wysiwyg',
							label: 'WYSIWYG',
							rendererComponent: resolve('./components/render.js'),
							pageContentComponent: resolve('./components/Editor.astro'),
						},
					],
				});
			},
		},
	});
}
